#include <iostream>
using namespace std;

class Student {
public:
    string name;
    int roll;
    void display() {
        cout << name << " (" << roll << ")" << endl;
    }
};

int main() {
    Student s1 = {"Alice", 101};
    Student* ptr = &s1;

    // Access via pointer
    cout << ptr->name << endl;
    ptr->display();

    // Dynamic object
    Student* s2 = new Student{"Bob", 102};
    s2->display();
    delete s2;

    return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
    virtual void show() { cout << "Base" << endl; }
};

class Derived : public Base {
public:
    void show() override { cout << "Derived" << endl; }
    void onlyDerived() { cout << "Derived specific" << endl; }
};

int main() {
    Base* bptr;
    Derived d;
    bptr = &d;   // base pointer to derived object
    bptr->show(); // Derived (due to virtual)
    // bptr->onlyDerived(); // ERROR: base pointer doesn't know derived members

    // Downcasting (use dynamic_cast)
    Derived* dptr = dynamic_cast<Derived*>(bptr);
    if (dptr) dptr->onlyDerived();

    return 0;
}

#include <iostream>
