}

#include <iostream>
using namespace std;

class Base {
public:
    Base() { cout << "Base ctor" << endl; }
    // virtual ~Base() { cout << "Base dtor" << endl; } // correct
    ~Base() { cout << "Base dtor" << endl; } // non-virtual - problem
};

class Derived : public Base {
public:
    int* data;
    Derived() : data(new int[100]) { cout << "Derived ctor, allocated memory" << endl; }
    ~Derived() { delete[] data; cout << "Derived dtor, freed memory" << endl; }
};

int main() {
    Base* ptr = new Derived();
    delete ptr;  // Without virtual ~Base(), only Base destructor called → memory leak!
    return 0;
}

#include <iostream>
using namespace std;

class Calculator {
public:
    int add(int a, int b) { return a + b; }
    int multiply(int a, int b) { return a * b; }
};

int main() {
    // Pointer to member function of Calculator that takes two ints and returns int
    int (Calculator::*funcPtr)(int, int);

    Calculator calc;
    funcPtr = &Calculator::add;
    cout << (calc.*funcPtr)(3, 4) << endl;  // 7

    funcPtr = &Calculator::multiply;
    cout << (calc.*funcPtr)(3, 4) << endl;  // 12

    // Using with pointer to object
    Calculator* pCalc = &calc;
    cout << (pCalc->*funcPtr)(5, 6) << endl; // 30

    return 0;
}

#include <iostream>
using namespace std;

struct Person {
    string name;
    int age;
};

int main() {
    // Pointer to member 'age'
    int Person::*agePtr = &Person::age;
    string Person::*namePtr = &Person::name;

    Person p1 = {"Alice", 25};
    Person p2 = {"Bob", 30};

    cout << p1.*agePtr << endl;   // 25
    cout << p2.*namePtr << endl;   // Bob

    // Using with pointer to object
    Person* p = &p1;
    cout << p->*agePtr << endl;    // 25

    return 0;
}

#include <iostream>
using namespace std;

class Chainable {
private:
    int value;
public:
    Chainable& setValue(int v) {
        value = v;
        return *this;
    }
    Chainable& add(int v) {
        value += v;
        return *this;
    }
    Chainable& multiply(int v) {
        value *= v;
        return *this;
    }
    void print() const {
        cout << "Value: " << value << endl;
    }
};

int main() {
    Chainable obj;
    obj.setValue(5).add(3).multiply(2).print();  // 5+3=8, *2=16
    return 0;
}

#include <iostream>
#include <vector>
using namespace std;

class Media {
public:
    virtual void play() = 0;
    virtual ~Media() {}
};

class Audio : public Media {
public:
    void play() override { cout << "Playing audio" << endl; }
};

class Video : public Media {
public:
    void play() override { cout << "Playing video" << endl; }
};

int main() {
    const int SIZE = 3;
    Media* playlist[SIZE];
    playlist[0] = new Audio();
    playlist[1] = new Video();
    playlist[2] = new Audio();

    for (int i = 0; i < SIZE; i++) {
        playlist[i]->play();
        delete playlist[i];
    }

    // Better: vector of smart pointers
    vector<unique_ptr<Media>> vec;
    vec.push_back(make_unique<Audio>());
    vec.push_back(make_unique<Video>());
    for (auto& m : vec) m->play();

    return 0;
}

#include <iostream>
using namespace std;

class Complex {
    double re, im;
public:
    Complex(double r = 0, double i = 0) : re(r), im(i) {
        cout << "Complex created: " << re << "+" << im << "i" << endl;
    }
    ~Complex() {
        cout << "Complex destroyed: " << re << "+" << im << "i" << endl;
    }
    void display() const {
        cout << re << " + " << im << "i" << endl;
    }
};

int main() {
    Complex* c1 = new Complex(3, 4);
    c1->display();
    delete c1;  // destructor called

    // Array of objects
    Complex* arr = new Complex[3]{{1,1}, {2,2}, {3,3}};
    delete[] arr;

    return 0;
}

#include <iostream>
using namespace std;

// Using function pointers
void dogSound() { cout << "Woof" << endl; }
void catSound() { cout << "Meow" << endl; }

// Using virtual functions
class Animal {
public:
    virtual void sound() = 0;
};
class Dog : public Animal { void sound() override { cout << "Woof" << endl; } };
class Cat : public Animal { void sound() override { cout << "Meow" << endl; } };

int main() {
    // Function pointer approach
    void (*sounds[2])() = {dogSound, catSound};
    for (int i = 0; i < 2; i++) sounds[i]();

    // Virtual function approach (more OOP)
    Animal* animals[2] = {new Dog(), new Cat()};
    for (auto a : animals) a->sound();
    for (auto a : animals) delete a;

    return 0;
}
